glsl3.vert:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
#if USE_LOCAL
  layout(std140) uniform CCLocal {
    highp mat4 cc_matWorld;
    highp mat4 cc_matWorldIT;
    highp vec4 cc_lightingMapUVParam;
    highp vec4 cc_localShadowBias;
    highp vec4 cc_reflectionProbeData1;
    highp vec4 cc_reflectionProbeData2;
    highp vec4 cc_reflectionProbeBlendData1;
    highp vec4 cc_reflectionProbeBlendData2;
  };
#endif
in vec3 a_position;
in vec2 a_texCoord;
in vec4 a_color;
out vec4 color;
out vec2 uv0;
vec4 vert () {
  vec4 pos = vec4(a_position, 1);
  #if USE_LOCAL
    pos = cc_matWorld * pos;
  #endif
  pos = cc_matViewProj * pos;
  uv0 = a_texCoord;
  color = a_color;
  return pos;
}
void main() { gl_Position = vert(); }

glsl3.frag:
precision highp float;
vec4 CCSampleWithAlphaSeparated(sampler2D tex, vec2 uv) {
#if CC_USE_EMBEDDED_ALPHA
  return vec4(texture(tex, uv).rgb, texture(tex, uv + vec2(0.0, 0.5)).r);
#else
  return texture(tex, uv);
#endif
}
#if USE_ALPHA_TEST
  layout(std140) uniform ALPHA_TEST_DATA {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
    if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
    if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 color;
in vec2 uv0;
uniform sampler2D cc_spriteTexture;
layout(std140) uniform EdgeCurrentParams {
  vec4 currentTime;
  vec4 currentColor;
  vec4 currentParams;
  vec4 currentScreenRect;
};
vec4 frag () {
  vec4 o = CCSampleWithAlphaSeparated(cc_spriteTexture, uv0) * color;
  float centerAlpha = o.a;
  vec2 sampleStep = vec2(0.003, 0.003);
  float alphaL = CCSampleWithAlphaSeparated(cc_spriteTexture, uv0 + vec2(-sampleStep.x, 0.0)).a * color.a;
  float alphaR = CCSampleWithAlphaSeparated(cc_spriteTexture, uv0 + vec2(sampleStep.x, 0.0)).a * color.a;
  float alphaB = CCSampleWithAlphaSeparated(cc_spriteTexture, uv0 + vec2(0.0, -sampleStep.y)).a * color.a;
  float alphaT = CCSampleWithAlphaSeparated(cc_spriteTexture, uv0 + vec2(0.0, sampleStep.y)).a * color.a;
  float alphaDelta = max(max(abs(centerAlpha - alphaL), abs(centerAlpha - alphaR)), max(abs(centerAlpha - alphaB), abs(centerAlpha - alphaT)));
  float spriteMask = smoothstep(0.02, 0.18, centerAlpha);
  float outlineMask = spriteMask * smoothstep(0.004, 0.055, alphaDelta);
  float edgeWidth = max(currentParams.x, 0.001);
  float intensity = currentParams.y;
  float shineCount = max(currentParams.z, 1.0);
  float t = currentTime.x * currentParams.w;
  vec2 currentUV = (gl_FragCoord.xy - currentScreenRect.xy) / max(currentScreenRect.zw, vec2(1.0, 1.0)) + vec2(0.5, 0.5);
  float insideMask = step(0.0, currentUV.x) * step(currentUV.x, 1.0) * step(0.0, currentUV.y) * step(currentUV.y, 1.0);
  float edgeDist = min(min(currentUV.x, 1.0 - currentUV.x), min(currentUV.y, 1.0 - currentUV.y));
  float outerBand = 1.0 - smoothstep(edgeWidth * 0.45, edgeWidth * 1.35, edgeDist);
  float coreMask = insideMask * spriteMask * outerBand;
  float glowMask = insideMask * max(outlineMask, spriteMask * outerBand * 0.65);
  vec2 centered = currentUV - vec2(0.5, 0.5);
  float perimeter = atan(centered.y, centered.x) / 6.2831853 + 0.5;
  float flow = fract(perimeter * shineCount - t);
  float distToHead = min(flow, 1.0 - flow);
  float head = 1.0 - smoothstep(0.0, 0.08, distToHead);
  float tail = (1.0 - smoothstep(0.08, 0.34, flow)) * smoothstep(0.0, 0.025, flow);
  float shine = max(head, tail * 0.72);
  float baseGlow = 0.05 + 0.02 * sin(perimeter * 25.0);
  float current = coreMask * (baseGlow + shine * 1.85);
  float glow = glowMask * (baseGlow * 0.45 + shine * 0.68);
  o.rgb += currentColor.rgb * (current * intensity + glow * intensity * 0.85) * currentColor.a;
  o.rgb += vec3(0.78, 1.0, 1.0) * coreMask * shine * intensity * 0.45;
  o.a = max(o.a, (current * 1.05 + glow * 0.7) * currentColor.a);
  ALPHA_TEST(o);
  return o;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

